/**
 * @param x The x-coordinate of the other point
 * @param y The y-coordinate of the other point
 * @return the squared distance between this point and the other point.
 */
public float dst2(int x, int y) {
    int xd = x - this.x;
    int yd = y - this.y;
    return xd * xd + yd * yd;
}
